const uid = () => Date.now().toString(36) + Math.random().toString(36).slice(2, 8);

// Detección de clientes duplicados: compara nombres sin acentos, mayúsculas
// ni espacios de más. "María López" ≈ "maria lopez" ≈ "Maria  Lopez ".
const normNombre = (s) =>
  (s || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/\s+/g, " ").trim();
const clientesParecidos = (nombre, clientes) => {
  const n = normNombre(nombre);
  if (n.length < 3) return [];
  return (clientes || []).filter((c) => {
    const cn = normNombre(c.nombre);
    return cn === n || cn.includes(n) || n.includes(cn);
  });
};

const todayISO = () => {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
};

const nowHM = () => {
  const d = new Date();
  return `${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`;
};

const moneyFmt = new Intl.NumberFormat("es-MX", { style: "currency", currency: "MXN" });
const money = (n) => moneyFmt.format(n || 0);

const fmtKg = (kg) => (Number.isInteger(kg) ? kg : kg.toFixed(1)) + " kg";

// Para el cliente hablamos en personas, no en kilos: 1 kg = 2 personas.
const fmtPersonas = (kg) => {
  const n = Math.max(1, Math.round(kg * 2));
  return `para ${n} persona${n === 1 ? "" : "s"}`;
};

const fmtHora12 = (hora24) => {
  if (!hora24) return "";
  const [h, m] = hora24.split(":").map(Number);
  const periodo = h >= 12 ? "PM" : "AM";
  let h12 = h % 12;
  if (h12 === 0) h12 = 12;
  return `${h12}:${String(m).padStart(2, "0")} ${periodo}`;
};

const fmtDateHuman = (iso) => {
  if (!iso) return "";
  const [y, m, d] = iso.split("-").map(Number);
  const date = new Date(y, m - 1, d);
  const s = date.toLocaleDateString("es-MX", { weekday: "long", day: "numeric", month: "long" });
  return s.charAt(0).toUpperCase() + s.slice(1);
};

const esHoy = (iso) => iso === todayISO();

// El subtotal de una paella = kilos × precio/kg + sus extras (langosta, chorizo...).
// Los extras no tocan el precio por kg: se suman aparte.
const sumaExtras = (extras) => (extras || []).reduce((a, e) => a + e.cantidad * e.precio, 0);
const calcPaellaSubtotal = (kg, precioKg, extras) => kg * precioKg + sumaExtras(extras);
// Texto corto de los extras de una paella: " + Langosta ×2 + Chorizo"
const resumenExtras = (it) =>
  (it.extras || []).map((e) => ` + ${e.nombre}${e.cantidad > 1 ? ` ×${e.cantidad}` : ""}`).join("");
const calcExtraSubtotal = (cantidad, precio) => cantidad * precio;

const computeTotal = (items) => items.reduce((acc, it) => acc + it.subtotal, 0);

// Costo de envío: solo aplica cuando el pedido es a domicilio.
const envioDe = (obj) => (obj.entrega ? parseFloat(obj.envio) || 0 : 0);

// IVA opcional (solo cuando el cliente lo pide, p. ej. facturación de eventos).
const IVA_TASA = 0.16;
const ivaDe = (obj) => (obj.iva ? (computeTotal(obj.items) + envioDe(obj)) * IVA_TASA : 0);
const totalDe = (obj) => computeTotal(obj.items) + envioDe(obj) + ivaDe(obj);

const resumenProductos = (items) => {
  if (!items || items.length === 0) return "Sin productos";
  return items
    .map((it) =>
      it.tipo === "paella"
        ? `${it.paellaNombre} (${fmtKg(it.kg)}${it.enPaellera ? " · paellera" : ""})`
        : `${it.nombre} x${it.cantidad}`
    )
    .join(" · ");
};

const estadoPagoDe = (pagado, total) => {
  if (pagado <= 0) return "pendiente";
  if (pagado >= total - 0.5) return "pagado";
  return "parcial";
};

// Folio consecutivo: busca el mayor folio existente en la lista y suma 1.
const siguienteFolio = (lista) => lista.reduce((max, x) => Math.max(max, x.folio || 0), 0) + 1;
const fmtFolio = (n, prefijo = "") => (n ? `${prefijo}${String(n).padStart(4, "0")}` : "");

// Normaliza un teléfono para WhatsApp: solo dígitos; si son 10 (México), antepone 52.
const telWhatsApp = (tel) => {
  const d = (tel || "").replace(/\D/g, "");
  if (!d) return "";
  return d.length === 10 ? "52" + d : d;
};

const aplicarPlantillaMensaje = (texto, datos) => {
  const nombre = (datos.clienteNombre || "").split(/\s+/)[0] || "";
  const folio = datos.folio ? fmtFolio(datos.folio) : "";
  return (texto || "").replaceAll("{nombre}", nombre).replaceAll("{folio}", folio);
};

// Texto de resumen para mandar por WhatsApp (pedido o presupuesto).
// `pago` son los datos bancarios de Ajustes para ofrecer el anticipo.
// `mensajes` son las plantillas editables de Ajustes → Datos.
const mensajeWhatsApp = (datos, modo, pago, mensajes) => {
  const lineas = [];
  const nombre = (datos.clienteNombre || "").split(/\s+/)[0];
  if (modo === "pedido") {
    lineas.push(aplicarPlantillaMensaje(mensajes?.saludoPedido || MENSAJES_DEFAULT.saludoPedido, datos));
  } else {
    lineas.push(`¡Hola${nombre ? " " + nombre : ""}! Le compartimos el resumen de su presupuesto en Pepe Andaluz 🥘`);
  }
  if (datos.folio) lineas.push(`Folio: ${fmtFolio(datos.folio, modo === "presupuesto" ? "P-" : "")}`);
  lineas.push("");
  lineas.push(`📅 ${fmtDateHuman(datos.fecha)} · ${fmtHora12(datos.hora)}`);
  lineas.push(datos.entrega ? "🚚 Entrega a domicilio" : "🏠 Para recoger en el local");
  lineas.push("");
  datos.items.forEach((it) => {
    if (it.tipo === "paella") {
      lineas.push(`• ${it.paellaNombre} ${fmtPersonas(it.kg)} — ${money(it.kg * it.precioKg)}`);
      (it.extras || []).forEach((e) => {
        lineas.push(`   + Extra ${e.nombre}${e.cantidad > 1 ? ` ×${e.cantidad}` : ""} — ${money(e.precio * e.cantidad)}`);
      });
    } else {
      lineas.push(`• ${it.nombre} ${it.unidad === "kg" ? "— " + fmtKg(it.cantidad) : it.piezasPorUnidad > 0 ? "— " + (it.cantidad * it.piezasPorUnidad) + " piezas" : "× " + it.cantidad} — ${money(it.subtotal)}`);
    }
  });
  lineas.push("");
  const envio = envioDe(datos);
  if (envio > 0) lineas.push(`Envío a domicilio: ${money(envio)}`);
  const iva = ivaDe(datos);
  if (iva > 0) lineas.push(`IVA (16%): ${money(iva)}`);
  const total = computeTotal(datos.items) + envio + iva;
  lineas.push(`Total: ${money(total)}`);
  if (modo === "pedido") {
    const pagado = sumaAbonos(datos.abonos);
    if (pagado > 0) {
      lineas.push(`Anticipo recibido: ${money(pagado)}`);
      lineas.push(`Saldo pendiente: ${money(Math.max(total - pagado, 0))}`);
    }
  }
  // Datos de pago: solo si están configurados y todavía hay algo por cobrar.
  const pagadoYa = sumaAbonos(datos.abonos);
  if (pago && (pago.clabe || "").trim() && pagadoYa < total) {
    lineas.push("");
    lineas.push("💳 Para confirmar su pedido se requiere el 50% de anticipo; el resto se liquida a la entrega.");
    if (pago.banco) lineas.push(`Banco: ${pago.banco}`);
    if (pago.titular) lineas.push(`A nombre de: ${pago.titular}`);
    lineas.push(`CLABE / Tarjeta: ${pago.clabe}`);
    lineas.push("Por favor, en el concepto de la transferencia ponga únicamente su nombre.");
  }
  lineas.push("");
  lineas.push(
    modo === "pedido"
      ? aplicarPlantillaMensaje(mensajes?.cierrePedido || MENSAJES_DEFAULT.cierrePedido, datos)
      : "¡Gracias por su preferencia!"
  );
  return lineas.join("\n");
};

// Mensaje corto para avisar que el pedido ya está listo (al marcarlo "Avisar"),
