// Unidades disponibles para definir los rangos de un envase desechable.
const UNIDADES_ENVASE = [
  { id: "kg", label: "kilos", sufijo: "kg" },
  { id: "piezas", label: "piezas", sufijo: "pzas" },
  { id: "litros", label: "litros", sufijo: "L" },
];

// Migra envases guardados antes de que tuvieran "unidad" (usaban solo kgMin/kgMax).
const normalizarDesechable = (d) => ({
  ...d,
  unidad: d.unidad || "kg",
  rangoMin: d.rangoMin != null ? d.rangoMin : d.kgMin || 0,
  rangoMax: d.rangoMax != null ? d.rangoMax : d.kgMax != null ? d.kgMax : 999,
});

// Nombre para identificar una paellera: el que le puso el usuario, o si no
// tiene, su rango de kilos como respaldo.
const nombrePaellera = (t) => (t.nombre && t.nombre.trim() ? t.nombre.trim() : `Paellera ${t.rangoMin}-${t.rangoMax}kg`);

// Compara si un valor cae dentro de un rango (min, max]. Cuando min===max
// (un tamaño exacto, ej. "de 3 a 3 kg") ese rango sería imposible con
// "mayor que min" — en ese caso se compara con igualdad.
const enRango = (valor, min, max) => (min === max ? valor === min : valor > min && valor <= max);

// Calcula cuántos envases de cada tipo consume un pedido:
// - Paellas sin paellera: el envase cuyo rango en KILOS incluya los kilos de la paella.
// - Platillos con empaque "pieza": un envase por cada unidad pedida.
// - Platillos con empaque "rango": el envase cuyo rango en PIEZAS incluya el total pedido
//   (ej. 6 piezas → contenedor chico, 7 a 24 → contenedor grande).
const calcularConsumo = (items, desechables, extrasCatalogo) => {
  const consumo = {};
  const envases = (desechables || []).map(normalizarDesechable);
  (items || []).forEach((it) => {
    if (it.tipo === "paella" && !it.enPaellera) {
      const tier = envases.find((d) => d.unidad === "kg" && enRango(it.kg, d.rangoMin, d.rangoMax));
      if (tier) consumo[tier.id] = (consumo[tier.id] || 0) + 1;
    }
    // Platillos con empaque vinculado (ej. alioli en su envase, croquetas
    // en el contenedor que corresponda según cuántas piezas se pidieron).
    if (it.tipo === "extra") {
      const cat = (extrasCatalogo || []).find((e) => e.id === it.extraId);
      if (!cat || !cat.empaqueTipo || cat.empaqueTipo === "ninguno") return;
      if (cat.empaqueTipo === "pieza" && cat.empaqueEnvaseId) {
        consumo[cat.empaqueEnvaseId] = (consumo[cat.empaqueEnvaseId] || 0) + Math.ceil(it.cantidad);
      } else if (cat.empaqueTipo === "rango") {
        const totalPiezas = it.piezasPorUnidad > 0 ? it.cantidad * it.piezasPorUnidad : it.cantidad;
        const tier = envases.find((d) => d.unidad === "piezas" && enRango(totalPiezas, d.rangoMin, d.rangoMax));
        if (tier) consumo[tier.id] = (consumo[tier.id] || 0) + 1;
      }
    }
  });
  return consumo;
};

// direccion: "consumir" descuenta del stock, "restaurar" lo regresa (nunca baja de 0)
const ajustarStock = (desechables, consumo, direccion) =>
  (desechables || []).map((d) => {
    const cantidad = consumo[d.id] || 0;
    if (cantidad === 0) return d;
    const delta = direccion === "consumir" ? -cantidad : cantidad;
    return { ...d, stock: Math.max(0, Math.round((d.stock + delta) * 100) / 100) };
  });

// ---- Unidades de medida para ingredientes ----
// La app convierte entre unidades de la misma familia (peso: g/kg, volumen: ml/l,
// piezas: pza) para descontar en "presentaciones" (bolsas, cajas...) aunque el
// uso por kilo de paella esté en gramos o piezas.
const UNIDADES_MEDIDA = [
  { id: "g", label: "gramos", familia: "peso", factor: 1 },
  { id: "kg", label: "kilos", familia: "peso", factor: 1000 },
  { id: "ml", label: "mililitros", familia: "volumen", factor: 1 },
  { id: "l", label: "litros", familia: "volumen", factor: 1000 },
  { id: "pza", label: "piezas", familia: "piezas", factor: 1 },
];
const UNIDAD_INFO = Object.fromEntries(UNIDADES_MEDIDA.map((u) => [u.id, u]));
const PRESENTACIONES = ["bolsa", "caja", "paquete", "costal", "botella", "lata", "frasco", "pieza"];

// Migra ingredientes del modelo viejo (solo unidad/stock) al nuevo con presentación.
const normalizarIngrediente = (ing) => {
  if (ing.presentacionCantidad != null) return ing;
  const u = UNIDAD_INFO[ing.unidad] ? ing.unidad : "pza";
  return {
    ...ing,
    presentacionNombre: "paquete",
    presentacionCantidad: 1,
    presentacionUnidad: u,
    usoUnidad: u,
    porKg: ing.porKg || {},
  };
};

// Consumo de ingredientes EN PRESENTACIONES (bolsas/cajas) según la receta:
// (uso por kg × kilos del pedido, convertido a la unidad base) ÷ contenido de la presentación.
const calcularConsumoIngredientes = (items, ingredientes) => {
  const consumo = {};
  items.forEach((it) => {
    if (it.tipo !== "paella") return;
    (ingredientes || []).forEach((raw) => {
      const ing = normalizarIngrediente(raw);
      const porKg = (ing.porKg || {})[it.paellaId] || 0;
      if (porKg <= 0) return;
      const fUso = (UNIDAD_INFO[ing.usoUnidad] || { factor: 1 }).factor;
      const fPres = (UNIDAD_INFO[ing.presentacionUnidad] || { factor: 1 }).factor;
      const contenido = (ing.presentacionCantidad || 1) * fPres;
      if (contenido <= 0) return;
      consumo[ing.id] = (consumo[ing.id] || 0) + (porKg * it.kg * fUso) / contenido;
    });
  });
  return consumo;
};

// Resumen de producción de un conjunto de pedidos (normalmente los de un
// mismo día): cuántos kilos de cada paella, cuántas piezas de cada platillo
// (cada uno por separado, ej. "Croquetas de Bacalao" y "Croquetas de Jamón"
// no se juntan), y cuánto de cada ingrediente con receta (ej. camarón) hay
// que preparar. A diferencia de calcularConsumoIngredientes (que da "bolsas"
// a descontar del stock), aquí queremos la cantidad cruda en la unidad de
// uso del ingrediente (piezas, gramos...), que es lo que se necesita para
// pelar o sacar del congelador.
const produccionDelDia = (pedidosDelDia, config) => {
  const paellasKg = {}; // paellaId -> kg total
  const platillos = {}; // extraId -> cantidad total (piezas si aplica, si no unidades)
  const ingredientesUso = {}; // ingredienteId -> cantidad en su usoUnidad
  const sueltasPorPaella = {}; // paellaId -> kg de PAELLA_SUELTA_MAX_KG o menos: no cabe en ninguna paellera

  pedidosDelDia.forEach((p) => {
    (p.items || []).forEach((it) => {
      if (it.tipo === "paella") {
        paellasKg[it.paellaId] = (paellasKg[it.paellaId] || 0) + it.kg;
        if (it.kg <= PAELLA_SUELTA_MAX_KG) sueltasPorPaella[it.paellaId] = (sueltasPorPaella[it.paellaId] || 0) + it.kg;
      } else if (it.tipo === "extra") {
        // Cantidad convertida a piezas cuando aplica (ej. 4 órdenes de
        // "ración de 6" = 24 piezas): es lo que hay que sacar del
        // congelador para descongelar. Cada platillo/sabor por separado.
        // Se usan las "piezas por orden" ACTUALES de Ajustes (no el valor
        // que el pedido guardó al crearse): si ese número se definió o
        // cambió después de que ya existían pedidos, esos pedidos viejos
        // no se cuentan de menos.
        const catalogo = (config.extras || []).find((e) => e.id === it.extraId);
        const piezasPorUnidad = catalogo ? catalogo.piezasPorUnidad || 0 : it.piezasPorUnidad || 0;
        const cant = piezasPorUnidad > 0 ? it.cantidad * piezasPorUnidad : it.cantidad;
        platillos[it.extraId] = (platillos[it.extraId] || 0) + cant;
      }
    });
  });

  // Solo ingredientes marcados explícitamente (ej. camarón, que se pela con
  // anticipación) — el resto de la receta no hace falta anunciarlo aquí.
  (config.ingredientes || []).filter((raw) => raw.avisarProduccion).forEach((raw) => {
    const ing = normalizarIngrediente(raw);
    let total = 0;
    Object.entries(paellasKg).forEach(([paellaId, kg]) => {
      const porKg = (ing.porKg || {})[paellaId] || 0;
      total += porKg * kg;
    });
    if (total > 0) ingredientesUso[ing.id] = total;
  });

  return { paellasKg, platillos, ingredientesUso, sueltasPorPaella };
};

// Paelleras (los recipientes grandes que se prestan al cliente) necesarias
// un día, según el rango de kilos de cada paella configurado en Ajustes →
// Inventario. Las paellas de PAELLA_SUELTA_MAX_KG o menos no caben en
// ninguna paellera y se cuentan aparte como "sueltas".
const PAELLA_SUELTA_MAX_KG = 2;
const paellerasDelDia = (pedidosDelDia, paelleras) => {
  const conteo = {}; // paelleraId -> cuántas se necesitan
  pedidosDelDia.forEach((p) => {
    (p.items || []).forEach((it) => {
      if (it.tipo !== "paella" || it.kg <= PAELLA_SUELTA_MAX_KG) return;
      const tier = (paelleras || []).find((t) => enRango(it.kg, t.rangoMin, t.rangoMax));
      if (tier) conteo[tier.id] = (conteo[tier.id] || 0) + 1;
    });
  });
  return conteo;
};

// Capacidad de cocina: cuántas paellas (líneas, no kilos) hay agendadas el
// mismo día dentro de ±30 min de una hora, sin contar el pedido que se está
// guardando (para no contarlo dos veces al editar).
const MAX_PAELLAS_POR_FRANJA = 5;
const minutosDeHora = (hora) => {
  const [h, m] = (hora || "00:00").split(":").map(Number);
  return h * 60 + m;
};
const contarPaellasEnFranja = (pedidos, fecha, hora, excluirId) => {
  const centro = minutosDeHora(hora);
  let total = 0;
  pedidos.forEach((p) => {
    if (p.id === excluirId || p.fecha !== fecha) return;
    if (Math.abs(minutosDeHora(p.hora) - centro) > 30) return;
    total += p.items.filter((it) => it.tipo === "paella").length;
  });
  return total;
};

// Compatibilidad con pedidos guardados antes de que la paellera fuera por platillo:
// si el pedido viejo tenía paellera a nivel general, se aplica a sus paellas.
// Asigna folio consecutivo a los registros que aún no lo tengan (datos viejos),
// respetando el orden de creación para que los folios queden cronológicos.
const asignarFolios = (lista) => {
  let max = lista.reduce((m, x) => Math.max(m, x.folio || 0), 0);
  const sinFolio = lista.filter((x) => !x.folio).sort((a, b) => (a.createdAt || 0) - (b.createdAt || 0));
  const mapa = new Map(sinFolio.map((x) => [x.id, ++max]));
  return lista.map((x) => (x.folio ? x : { ...x, folio: mapa.get(x.id) }));
};

const migrarPedido = (p) => {
  const items = (p.items || []).map((it) => {
    if (it.tipo !== "paella") return it;
    return {
      ...it,
      enPaellera: it.enPaellera !== undefined ? it.enPaellera : !!p.paellera,
      paelleraDevuelta: it.paelleraDevuelta !== undefined ? it.paelleraDevuelta : !!p.paelleraDevuelta,
    };
  });
  const { paellera, paelleraDevuelta, ...resto } = p;
  // Migra el pago viejo (un monto + un método) a la lista de abonos, que
  // permite mezclar formas de pago (ej. anticipo por transferencia, resto en efectivo).
  const abonos = p.abonos || (p.pagado > 0 ? [{ id: uid(), monto: p.pagado, metodo: p.metodoPago || "efectivo" }] : []);
  return { ...resto, items, estado: p.estado || "pendiente", abonos };
};

const sumaAbonos = (abonos) => (abonos || []).reduce((a, x) => a + (parseFloat(x.monto) || 0), 0);

