// Input numérico con memoria propia: se puede borrar y escribir libremente
// mientras se edita, y solo se valida/redondea al salir del campo.
function NumberField({ value, onChange, min, className, disabled }) {
  const [text, setText] = useState(String(value));
  useEffect(() => { setText(String(value)); }, [value]);

  const commit = () => {
    const v = parseFloat(text);
    const limpio = Number.isNaN(v) ? (min != null ? min : 0) : (min != null ? Math.max(min, v) : v);
    onChange(limpio);
    setText(String(limpio));
  };

  return (
    <input
      type="text"
      inputMode="decimal"
      className={className}
      value={text}
      disabled={disabled}
      onFocus={(e) => e.target.select()}
      onChange={(e) => setText(e.target.value)}
      onBlur={commit}
      onKeyDown={(e) => { if (e.key === "Enter") e.target.blur(); }}
    />
  );
}

function Stepper({ value, onChange, min = 1, step = 1 }) {
  return (
    <div className="flex items-center gap-2">
      <button type="button" className="af-stepper-btn" onClick={() => onChange(Math.max(min, +(value - step).toFixed(2)))}>
        <Minus size={14} />
      </button>
      <NumberField value={value} min={min} className="af-stepper-input" onChange={onChange} />
      <button type="button" className="af-stepper-btn" onClick={() => onChange(+(value + step).toFixed(2))}>
        <Plus size={14} />
      </button>
    </div>
  );
}

// Campo para la ubicación: se puede escribir/pegar a mano, o con el botón
// se toma directo del portapapeles (para cuando copian el link desde WhatsApp).
function UbicacionField({ value, onChange, placeholder }) {
  const pegar = async () => {
    try {
      const texto = await navigator.clipboard.readText();
      if (texto) onChange(texto.trim());
    } catch (e) {
      // El navegador puede negar el permiso de portapapeles; no pasa nada,
      // igual se puede pegar a mano con Cmd/Ctrl+V.
    }
  };
  return (
    <div className="af-ubic-row">
      <input
        className="af-input"
        value={value}
        placeholder={placeholder || "Pega aquí el link de ubicación"}
        onChange={(e) => onChange(e.target.value)}
      />
      <button type="button" className="af-paste-btn" onClick={pegar} title="Pegar desde el portapapeles">
        <ClipboardPaste size={16} />
      </button>
    </div>
  );
}

