function LoginView({ onEntrar }) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [errorLogin, setErrorLogin] = useState("");
  const [entrando, setEntrando] = useState(false);

  const entrar = async () => {
    if (!email.trim() || !password) { setErrorLogin("Escribe tu correo y contraseña."); return; }
    setEntrando(true);
    setErrorLogin("");
    try {
      await onEntrar(email.trim(), password);
    } catch (e) {
      setErrorLogin(
        (e && e.message === "Invalid login credentials")
          ? "Correo o contraseña incorrectos."
          : "No se pudo iniciar sesión. Revisa tu conexión."
      );
    } finally {
      setEntrando(false);
    }
  };

  return (
    <div className="af-app af-login">
      <style>{AZAFRAN_CSS}</style>
      <div className="af-login-card">
        <div className="af-logo-mark af-logo-login" />
        <div className="af-login-sub">Inicia sesión para ver los pedidos</div>
        <div className="af-field">
          <label>Correo</label>
          <input
            className="af-input" type="email" autoComplete="username" placeholder="tu@correo.com"
            value={email} onChange={(e) => setEmail(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && entrar()}
          />
        </div>
        <div className="af-field">
          <label>Contraseña</label>
          <input
            className="af-input" type="password" autoComplete="current-password" placeholder="••••••••"
            value={password} onChange={(e) => setPassword(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && entrar()}
          />
        </div>
        {errorLogin && <div className="af-error">{errorLogin}</div>}
        <button className="af-btn-primary w-full" onClick={entrar} disabled={entrando}>
          {entrando ? "Entrando..." : "Entrar"}
        </button>
        <div className="af-hint mt-3" style={{ textAlign: "center" }}>
          ¿Sin cuenta? Pídele al administrador que te dé de alta.
        </div>
      </div>
    </div>
  );
}

